#include <bits/stdc++.h>
#define a first
#define b second
using namespace std;

const int M=5003,N=1e4+4;

struct Node{
    int l,r;
    bool tp;
}op[M];

int n,m,num[N],f[N];
bool s[N];
map<int,int> id;

pair<int,bool> father(int x){
    if(f[x]==x)
        return {x,0};
    pair<int,bool> tmp=father(f[x]);
    f[x]=tmp.a,s[x]^=tmp.b;
    return {f[x],s[x]};
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        char str[5];
        scanf("%d%d%s",&op[i].l,&op[i].r,str+1);
        op[i].r++,op[i].tp=(strlen(str+1)==3),num[i*2-1]=op[i].l,num[i*2]=op[i].r;
    }
    sort(num+1,num+2*m+1);
    n=unique(num+1,num+2*m+1)-num-1;
    for(int i=1;i<=n;i++)
        id[num[i]]=i,f[i]=i;
    for(int i=1;i<=m;i++){
        op[i].l=id[op[i].l],op[i].r=id[op[i].r];
        pair<int,bool> fl=father(op[i].l),fr=father(op[i].r);
        if(fl.a==fr.a){
            if((fl.b^fr.b)!=op[i].tp){
                printf("%d",i-1);
                return 0;
            }
        }else{
            if(fl.a<fr.a)
                f[fl.a]=fr.a,s[fl.a]=fl.b^fr.b^op[i].tp;
            else
                f[fr.a]=fl.a,s[fr.a]=fl.b^fr.b^op[i].tp;
        }
    }
    printf("%d",m);
    return 0;
}
